Here's a solid pattern using `MockHttpMessageHandler` and MSTest's async support:

```csharp
[TestClass]
public class DataFetcherTests
{
    // Helper: create a handler that returns a canned response
    private static HttpClient CreateMockClient(
        HttpStatusCode status, string content, TimeSpan? delay = null)
    {
        var handler = new MockHandler(status, content, delay);
        return new HttpClient(handler);
    }

    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        using var client = CreateMockClient(HttpStatusCode.OK, "hello");
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnNonSuccessStatus()
    {
        using var client = CreateMockClient(HttpStatusCode.InternalServerError, "");
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_Throws_WhenCancelled()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        using var client = CreateMockClient(HttpStatusCode.OK, "data");
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)] // MSTest-level safety net
    public async Task FetchAsync_Throws_WhenTimeoutExpires()
    {
        // Handler delays 10s, but token cancels after 100ms
        using var client = CreateMockClient(
            HttpStatusCode.OK, "slow", delay: TimeSpan.FromSeconds(10));
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(100));
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Minimal mock handler — no external dependency needed
    private class MockHandler : HttpMessageHandler
    {
        private readonly HttpStatusCode _status;
        private readonly string _content;
        private readonly TimeSpan? _delay;

        public MockHandler(HttpStatusCode status, string content, TimeSpan? delay)
        {
            _status = status;
            _content = content;
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();

            if (_delay is { } d)
                await Task.Delay(d, cancellationToken);

            return new HttpResponseMessage(_status)
            {
                Content = new StringContent(_content)
            };
        }
    }
}
```

**Key patterns:**

- **Mock at `HttpMessageHandler`** — avoids mocking `HttpClient` directly (its methods aren't virtual).
- **Pre-cancelled token** — tests the immediate cancellation path.
- **`CancellationTokenSource(timeout)`** — simulates a real timeout without slowing your suite down.
- **`[Timeout(5000)]`** — MSTest safety net so a broken test can't hang your CI indefinitely.
- **`using`** on `HttpClient` and `CancellationTokenSource` — prevents resource leaks across tests.
